class Solution(object):
    def maxHeightOfTriangle(self, red, blue):
        def maxH(a, b):
            h, ra, rb = 0, a, b
            while True:
                need = h + 1
                if h % 2 == 0:
                    if ra >= need:
                        ra -= need
                        h += 1
                    else:
                        break
                else:
                    if rb >= need:
                        rb -= need
                        h += 1
                    else:
                        break
            return h
        return max(maxH(red, blue), maxH(blue, red))
